from functools import lru_cache

class Solution:
    def getMaximumGenerated(self, n):
        if n == 0:
            return 0

        @lru_cache(maxsize=None)
        def f(i):
            if i == 0:
                return 0
            if i == 1:
                return 1
            if i % 2 == 0:
                return f(i // 2)
            return f(i // 2) + f(i // 2 + 1)

        best = max(f(i) for i in range(n + 1))
        f.cache_clear()
        return best

